// Generated by GitHub Copilot
import '@testing-library/jest-dom/vitest';
import { cleanup, render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { afterEach, beforeEach, describe, expect, it } from 'vitest';
import App from './App';

/**
 * Logs in with the given credentials and waits for the home heading.
 * @param {import('@testing-library/user-event').UserEvent} user
 * @param {string} email
 * @param {string} password
 */
async function loginAs(user, email, password) {
  const emailInput = await screen.findByLabelText(/Correo electrónico|Email/i);
  const passwordInput = await screen.findByLabelText(/Contraseña|Password/i);
  const submitBtn = await screen.findByRole('button', { name: /Entrar|Sign in/i });
  await user.type(emailInput, email);
  await user.type(passwordInput, password);
  await user.click(submitBtn);
}

describe('App integration', () => {
  beforeEach(() => {
    localStorage.clear();
    window.history.pushState({}, '', '/');
  });

  afterEach(() => {
    cleanup();
  });

  it('client: login → add product → cart shows item', async () => {
    const user = userEvent.setup();
    render(<App />);

    await loginAs(user, 'cliente@tienda.com', 'Cliente123');

    await waitFor(() => {
      expect(screen.getByRole('heading', { name: /Nuestros Productos|Products/i })).toBeInTheDocument();
    });

    const addButtons = await screen.findAllByRole('button', { name: /Añadir producto|Agregar producto|Add product/i });
    expect(addButtons.length).toBeGreaterThan(0);

    await user.click(addButtons[0]);
    await user.click(screen.getByRole('link', { name: /Carrito|Cart/i }));

    await waitFor(() => {
      expect(screen.getByRole('heading', { name: /Carrito|Cart/i })).toBeInTheDocument();
    });

    // At least one quantity-control group confirms the cart has item rows.
    expect(screen.getAllByRole('group').length).toBeGreaterThan(0);
  });

  it('admin: login → no cart/buy buttons visible in product grid', async () => {
    const user = userEvent.setup();
    render(<App />);

    await loginAs(user, 'admin@tienda.com', 'Admin123');

    await waitFor(() => {
      expect(screen.getByRole('heading', { name: /Nuestros Productos|Products/i })).toBeInTheDocument();
    });

    // Admin should NOT see add-to-cart or buy buttons.
    expect(screen.queryAllByRole('button', { name: /Añadir producto|Add product/i })).toHaveLength(0);
    expect(screen.queryAllByRole('button', { name: /Comprar|Buy/i })).toHaveLength(0);
    expect(screen.queryByRole('link', { name: /Carrito|Cart/i })).not.toBeInTheDocument();
  });

  it('client: cart persists after simulated page reload', async () => {
    const user = userEvent.setup();
    const { unmount } = render(<App />);

    await loginAs(user, 'cliente@tienda.com', 'Cliente123');

    await waitFor(() => {
      expect(screen.getByRole('heading', { name: /Nuestros Productos|Products/i })).toBeInTheDocument();
    });

    const addButtons = await screen.findAllByRole('button', { name: /Añadir producto|Agregar producto|Add product/i });
    await user.click(addButtons[0]);

    // Simulate reload: unmount and remount with same localStorage.
    unmount();
    window.history.pushState({}, '', '/');
    render(<App />);

    // After reload user is still authenticated (role in localStorage) and reaches home.
    await waitFor(() => {
      expect(screen.getByRole('heading', { name: /Nuestros Productos|Products/i })).toBeInTheDocument();
    });

    // Navigate to cart and confirm the item is still there.
    await user.click(screen.getByRole('link', { name: /Carrito|Cart/i }));

    await waitFor(() => {
      expect(screen.getByRole('heading', { name: /Carrito|Cart/i })).toBeInTheDocument();
    });

    expect(screen.getAllByRole('group').length).toBeGreaterThan(0);
  });
});
